import{c as h,S as t,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Đánh giá đầu vào","description":"","frontmatter":{},"headers":[],"relativePath":"admin/danh-gia-dau-vao.md","filePath":"admin/danh-gia-dau-vao.md","lastUpdated":0}'),o={name:"admin/danh-gia-dau-vao.md"};function l(g,n,r,c,s,e){return t(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="đanh-gia-đau-vao" tabindex="-1">Đánh giá đầu vào <a class="header-anchor" href="#đanh-gia-đau-vao" aria-label="Permalink to “Đánh giá đầu vào”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/evaluation</code></p><p>Đánh giá đầu vào (Kiểm tra đầu vào) là <strong>bài test đo trình độ học viên trước khi vào khóa học / lớp học</strong>. Kết quả giúp tư vấn lộ trình học phù hợp và phân loại học viên vào nhóm năng lực đúng.</p><h2 id="khi-nao-dung" tabindex="-1">Khi nào dùng <a class="header-anchor" href="#khi-nao-dung" aria-label="Permalink to “Khi nào dùng”">​</a></h2><ul><li>Học viên mới đăng ký, <strong>chưa rõ trình độ</strong> → cần test trước khi đề xuất khóa.</li><li>Trung tâm tổ chức <strong>tuyển sinh đầu vào</strong> cho lớp luyện thi.</li><li><strong>Phân lớp</strong> học viên theo trình độ (Cơ bản / Trung bình / Khá / Giỏi).</li><li>Đo <strong>điểm chuẩn ban đầu</strong> để so sánh với điểm sau khóa (đánh giá hiệu quả khóa).</li></ul><h2 id="phan-biet-voi-đe-thi-khac" tabindex="-1">Phân biệt với đề thi khác <a class="header-anchor" href="#phan-biet-voi-đe-thi-khac" aria-label="Permalink to “Phân biệt với đề thi khác”">​</a></h2><table tabindex="0"><thead><tr><th>Đề</th><th>Mục đích</th></tr></thead><tbody><tr><td><strong>Đánh giá đầu vào</strong></td><td>Test trình độ trước khóa, gắn với khóa cụ thể hoặc đứng độc lập</td></tr><tr><td><strong>Đề ôn khóa học</strong></td><td>Luyện tập sau khi đã trong khóa</td></tr><tr><td><strong>Đề mẫu Luyện thi</strong></td><td>Thi thử mô phỏng kỳ thi thật</td></tr></tbody></table><h2 id="danh-sach-bai-đanh-gia" tabindex="-1">Danh sách bài đánh giá <a class="header-anchor" href="#danh-sach-bai-đanh-gia" aria-label="Permalink to “Danh sách bài đánh giá”">​</a></h2><p>Cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên bài đánh giá</td><td>Vd &quot;Test đầu vào - Luyện thi HSA&quot;</td></tr><tr><td>Môn / Lĩnh vực</td><td>Toán / Văn / Anh / Tổng hợp…</td></tr><tr><td>Khóa liên kết</td><td>Khóa nào dùng làm test đầu vào (có thể trống nếu dùng độc lập)</td></tr><tr><td>Số câu</td><td></td></tr><tr><td>Thời gian (phút)</td><td></td></tr><tr><td>Số học viên đã làm</td><td></td></tr><tr><td>Trạng thái</td><td>Công khai / Nháp / Ẩn</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Môn</strong>.</li><li>Theo <strong>Khóa liên kết</strong>.</li><li>Theo <strong>Trạng thái</strong>.</li><li>Tìm kiếm theo <strong>Tên bài</strong>.</li></ul><h2 id="tao-moi-bai-đanh-gia" tabindex="-1">Tạo mới bài đánh giá <a class="header-anchor" href="#tao-moi-bai-đanh-gia" aria-label="Permalink to “Tạo mới bài đánh giá”">​</a></h2><ol><li>Bấm <strong>Thêm mới</strong>.</li><li>Khai báo: <ul><li><strong>Tên bài đánh giá</strong> (vd &quot;Test đầu vào - Luyện thi HSA 2026&quot;).</li><li><strong>Mô tả</strong>: hiển thị cho học viên trước khi làm.</li><li><strong>Hướng dẫn làm bài</strong>.</li><li><strong>Môn / Lĩnh vực</strong> áp dụng.</li><li><strong>Khóa liên kết</strong> (tùy chọn): khóa sẽ tự gọi bài test này.</li><li><strong>Thời gian làm bài</strong> (phút).</li><li><strong>Tổng điểm</strong> (mặc định 10 hoặc 100).</li></ul></li><li>Chọn <strong>chế độ dựng đề</strong>: <ul><li><strong>Cố định</strong>: chọn tay từng câu.</li><li><strong>Theo tiêu chí</strong>: chọn 1 <a href="./tieu-chi-de-thi">Tiêu chí đề thi</a> → hệ thống random.</li></ul></li><li>Cấu hình thêm: <ul><li><strong>Số lần làm</strong>: thường chỉ cho <strong>1 lần</strong> (đánh giá đầu vào không nên làm lại).</li><li><strong>Hiển thị đáp án sau khi nộp</strong>: thường <strong>Không</strong> để tránh học viên ghi nhớ rồi làm lại.</li><li><strong>Trộn câu / trộn đáp án</strong>.</li></ul></li><li>Cấu hình <strong>khung phân loại</strong> (xem mục kế).</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="chon-cau-hoi-che-đo-co-đinh" tabindex="-1">Chọn câu hỏi (chế độ Cố định) <a class="header-anchor" href="#chon-cau-hoi-che-đo-co-đinh" aria-label="Permalink to “Chọn câu hỏi (chế độ Cố định)”">​</a></h2><ol><li>Mở chi tiết bài đánh giá → tab <strong>Câu hỏi</strong>.</li><li>Bấm <strong>Thêm câu hỏi</strong> → chọn từ <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a>.</li><li>Khuyến nghị: chọn câu <strong>trải đều các mức độ</strong> (Nhận biết → Vận dụng cao) để đánh giá chính xác trình độ.</li><li>Sắp xếp thứ tự, sửa điểm.</li><li>Lưu.</li></ol><h2 id="cau-hinh-khung-phan-loai-phan-nguong" tabindex="-1">Cấu hình khung phân loại (Phân ngưỡng) <a class="header-anchor" href="#cau-hinh-khung-phan-loai-phan-nguong" aria-label="Permalink to “Cấu hình khung phân loại (Phân ngưỡng)”">​</a></h2><p>Khung phân loại giúp hệ thống <strong>tự gắn nhãn trình độ</strong> cho học viên dựa theo điểm:</p><ol><li><p>Trong chi tiết bài đánh giá, mở <strong>tab Phân loại</strong>.</p></li><li><p>Thêm các ngưỡng:</p><table tabindex="0"><thead><tr><th>Khoảng điểm</th><th>Nhãn</th><th>Khóa khuyến nghị</th></tr></thead><tbody><tr><td>0 - 4</td><td>Cơ bản</td><td>Khóa &quot;Nền tảng HSA&quot;</td></tr><tr><td>4.1 - 6.5</td><td>Trung bình</td><td>Khóa &quot;Tăng tốc HSA&quot;</td></tr><tr><td>6.6 - 8.5</td><td>Khá</td><td>Khóa &quot;Luyện đề thực chiến&quot;</td></tr><tr><td>8.6 - 10</td><td>Giỏi</td><td>Khóa &quot;Cao thủ HSA&quot;</td></tr></tbody></table></li><li><p>Khi học viên nộp bài, hệ thống tự tính và <strong>gợi ý khóa</strong> phù hợp ngay trên màn hình kết quả.</p></li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Khung phân loại cũng có thể dùng để <strong>phân lớp</strong>: học viên &gt;7 vào Lớp A, 5-7 vào Lớp B, &lt;5 vào Lớp C. Việc gán lớp được thực hiện ở <a href="./quan-ly-hoc-vien">Quản lý học viên</a>.</p></div><h2 id="gan-bai-đanh-gia-vao-khoa-hoc" tabindex="-1">Gán bài đánh giá vào khóa học <a class="header-anchor" href="#gan-bai-đanh-gia-vao-khoa-hoc" aria-label="Permalink to “Gán bài đánh giá vào khóa học”">​</a></h2><p>Có 2 cách:</p><h3 id="cach-1-trong-khoa-hoc" tabindex="-1">Cách 1: Trong <a href="./khoa-hoc">Khóa học</a> <a class="header-anchor" href="#cach-1-trong-khoa-hoc" aria-label="Permalink to “Cách 1: Trong Khóa học”">​</a></h3><ol><li>Vào chi tiết khóa.</li><li>Tab <strong>Kiểm tra đầu vào</strong> → chọn bài đánh giá đã tạo.</li><li>Lưu.</li></ol><p>→ Học viên mới mua khóa sẽ <strong>bắt buộc</strong> (hoặc tùy chọn) làm bài này trước khi học.</p><h3 id="cach-2-trong-bai-đanh-gia" tabindex="-1">Cách 2: Trong bài đánh giá <a class="header-anchor" href="#cach-2-trong-bai-đanh-gia" aria-label="Permalink to “Cách 2: Trong bài đánh giá”">​</a></h3><ol><li>Mở bài đánh giá → tab <strong>Khóa liên kết</strong>.</li><li>Bấm <strong>Thêm khóa</strong> → chọn 1 hoặc nhiều khóa.</li><li>Lưu.</li></ol><h2 id="test-đoc-lap-khong-gan-khoa" tabindex="-1">Test độc lập (không gắn khóa) <a class="header-anchor" href="#test-đoc-lap-khong-gan-khoa" aria-label="Permalink to “Test độc lập (không gắn khóa)”">​</a></h2><p>Bài đánh giá có thể đứng độc lập, dành cho <strong>học viên tiềm năng</strong> (chưa mua khóa nào):</p><ol><li>Tạo bài đánh giá, không liên kết khóa.</li><li>Đặt trạng thái <strong>Công khai</strong>.</li><li>Lấy <strong>link công khai</strong> (nút <strong>Sao chép link</strong> tại chi tiết bài).</li><li>Chia sẻ link cho người quan tâm — họ vào làm test, nhận kết quả + gợi ý khóa.</li><li>Dữ liệu sẽ chuyển về <a href="./quan-ly-nhan-vien">CRM / Bộ phận tư vấn</a> để chăm sóc.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Đây là cách hiệu quả để <strong>lead-gen</strong> (thu lead): học viên làm test, cung cấp số điện thoại / email, nhận tư vấn miễn phí.</p></div><h2 id="sua-bai-đanh-gia" tabindex="-1">Sửa bài đánh giá <a class="header-anchor" href="#sua-bai-đanh-gia" aria-label="Permalink to “Sửa bài đánh giá”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Sửa</strong>.</li><li>Cập nhật thông tin, câu hỏi, khung phân loại.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Sửa khung phân loại <strong>không ảnh hưởng</strong> đến học viên đã làm trước đó. Họ vẫn giữ nhãn theo khung cũ.</p></div><h2 id="xoa-bai-đanh-gia" tabindex="-1">Xóa bài đánh giá <a class="header-anchor" href="#xoa-bai-đanh-gia" aria-label="Permalink to “Xóa bài đánh giá”">​</a></h2><ol><li>Tại danh sách, bấm <strong>Xóa</strong>.</li><li>Xác nhận.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Bài đánh giá đã có lượt làm chỉ bị <strong>ẩn</strong>. Cân nhắc trước khi xóa vì sẽ mất gợi ý khóa của nhiều học viên.</p></div><h2 id="xem-ket-qua" tabindex="-1">Xem kết quả <a class="header-anchor" href="#xem-ket-qua" aria-label="Permalink to “Xem kết quả”">​</a></h2><ol><li>Mở chi tiết bài đánh giá → tab <strong>Kết quả</strong>.</li><li>Bảng hiển thị: <ul><li>Học viên, ngày làm, điểm, <strong>nhãn phân loại</strong>, <strong>khóa được gợi ý</strong>.</li><li>Có thể bấm vào dòng để xem chi tiết bài làm.</li></ul></li><li><strong>Xuất Excel</strong> danh sách → chuyển bộ phận tư vấn.</li><li><strong>Biểu đồ phân bố</strong> điểm theo nhãn — giúp đánh giá chất lượng học viên đầu vào theo đợt.</li></ol><h2 id="nhap-xuat" tabindex="-1">Nhập / Xuất <a class="header-anchor" href="#nhap-xuat" aria-label="Permalink to “Nhập / Xuất”">​</a></h2><ul><li><strong>Xuất Excel</strong> danh sách bài đánh giá kèm thống kê lượt làm.</li><li><strong>Xuất kết quả Excel</strong> từ tab Kết quả: học viên, điểm, nhãn, gợi ý khóa, thông tin liên hệ — dùng để chuyển CRM.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên đã làm test rồi nhưng muốn làm lại - cho phép không?</strong> → Không khuyến khích, vì học viên đã nhớ câu → kết quả không phản ánh đúng trình độ. Nếu thực sự cần, vào chi tiết kết quả → bấm <strong>Reset lượt làm</strong> cho học viên đó.</p><p><strong>Test đầu vào có miễn phí không?</strong> → Mặc định miễn phí. Nếu muốn thu phí, gắn vào khóa có phí hoặc dùng cơ chế &quot;trả phí mở test&quot; (liên hệ quản trị để bật).</p><p><strong>Tôi muốn 1 bài test áp dụng cho nhiều môn (Toán + Văn + Anh) - làm sao?</strong> → Tạo 1 bài đánh giá tổng hợp, chia câu hỏi theo từng môn trong cùng đề. Khung phân loại có thể chia điểm tổng hoặc xem điểm từng môn (cấu hình nâng cao).</p><p><strong>Có thể bắt buộc học viên làm test trước khi truy cập bài giảng không?</strong> → Có. Trong cấu hình <a href="./khoa-hoc">Khóa học</a>, bật tùy chọn &quot;Bắt buộc làm kiểm tra đầu vào trước khi học&quot;.</p><p><strong>Học viên không có thông tin liên hệ - làm sao tư vấn?</strong> → Khi làm test độc lập, bắt buộc học viên điền <strong>Họ tên + Số điện thoại / Email</strong> trước khi xem kết quả. Bật trường này trong cấu hình bài.</p><p><strong>Khung phân loại không hợp lý - học viên làm rất tốt nhưng bị xếp Trung bình.</strong> → Mở <strong>tab Phân loại</strong> → điều chỉnh ngưỡng điểm. Lưu ý: chỉ áp dụng cho lượt làm sau.</p><p><strong>Có gợi ý khóa cho học viên dựa trên ĐIỂM TỪNG MÔN, không phải điểm tổng?</strong> → Cấu hình nâng cao trong khung phân loại: chia &quot;Phần&quot; → đặt ngưỡng riêng cho từng phần → ánh xạ sang khóa khác nhau. Liên hệ quản trị nếu chưa thấy giao diện này.</p>',49)])])}const p=h(o,[["render",l]]);export{d as __pageData,p as default};
